{"name": "write_file", "arguments": {"path": "src/utils/validateUser.ts", "content": "import type { User } from '../types/user';

export function validateUser(data: unknown): data is User {
  if (!data || typeof data !== 'object') return false;
  const obj = data as Record<string, unknown>;

  if (typeof obj.id !== 'number' || obj.id <= 0) return false;
  if (typeof obj.name !== 'string' || obj.name.trim().length === 0) return false;
  if (typeof obj.email !== 'string' || !obj.email.includes('@')) return false;
  if (!['admin', 'user', 'viewer'].includes(obj.role as string)) return false;
  if (!(obj.createdAt instanceof Date) || isNaN(obj.createdAt.getTime())) return false;

  return true;
}"}}
